#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>

#define MOD 1000000007LL

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long *a = (long long*)malloc(N*sizeof(long long));
        for(int i=0;i<N;i++) scanf("%lld", &a[i]);
        long long *dp = (long long*)calloc(N+1, sizeof(long long));
        dp[0] = 1; // empty product
        for(int i=1;i<=N;i++){
            long long best = 0;
            // try every split point j
            for(int j=0;j<i;j++){
                // compute distinct count in a[j..i-1]
                int seen[32]; // simple hash set for up to 15 values, use linear search
                int cnt = 0;
                for(int k=j;k<i;k++){
                    int present = 0;
                    for(int s=0;s<cnt;s++) if(seen[s]==a[k]){ present=1; break; }
                    if(!present) seen[cnt++] = a[k];
                }
                long long cand = dp[j] * cnt;
                if(cand > best) best = cand;
            }
            dp[i] = best;
        }
        printf("%lld\n", dp[N] % MOD);
        free(a);
        free(dp);
    }
    return 0;
}

