    while(T--){
        int N; cin>>N;
        vector<long long> a(N);
        for(int i=0;i<N;i++) cin>>a[i];
        vector<long long> dp(N+1,0);
        dp[0]=1;
        for(int i=1;i<=N;i++){
            long long best=0;
            for(int j=0;j<i;j++){
                unordered_set<long long> st;
                for(int k=j;k<i;k++) st.insert(a[k]);
                long long cand = dp[j] * (long long)st.size();
                if(cand>best) best=cand;
            }
            dp[i]=best;
        }
        cout << (dp[N]%MOD) << '\n';
    }
    return 0;
}

