  for(let i=0;i<N;i++) a[i] = Number(next());
  let dp = new Array(N+1).fill(0n);
  dp[0] = 1n;
  for(let i=1;i<=N;i++){
    let best = 0n;
    for(let j=0;j<i;j++){
      // distinct count in a[j..i-1]
      const seen = new Set();
      for(let k=j;k<i;k++) seen.add(a[k]);
      const distinct = BigInt(seen.size);
      const cand = dp[j] * distinct;
      if(cand > best) best = cand;
    }
    dp[i] = best;
  }
  outputs.push(String(dp[N] % MOD));
}
